    35→      const input = screen.getByPlaceholderText('Cerca materiali...');
    36→      expect(input).toBeInTheDocument();
    37→    });
    38→
    39→    it('should display current value', () => {
    40→      render(<SearchBar value="test query" onChange={vi.fn()} />);
    41→
    42→      const input = screen.getByRole('searchbox');
    43→      expect(input).toHaveValue('test query');
    44→    });
    45→
    46→    it('should show clear button when value exists', () => {
    47→      render(<SearchBar value="test" onChange={vi.fn()} />);
    48→
    49→      const clearButton = screen.getByLabelText('Cancella ricerca');
    50→      expect(clearButton).toBeInTheDocument();
    51→    });
    52→
    53→    it('should not show clear button when empty', () => {
    54→      render(<SearchBar value="" onChange={vi.fn()} />);
    55→
    56→      const clearButton = screen.queryByLabelText('Cancella ricerca');
    57→      expect(clearButton).not.toBeInTheDocument();
    58→    });
    59→  });
    60→
    61→  describe('Debounced Search', () => {
    62→    it('should debounce search input', async () => {
    63→      const onChange = vi.fn();
    64→      render(<SearchBar value="" onChange={onChange} debounceMs={300} />);
    65→
    66→      const input = screen.getByRole('searchbox');
    67→      fireEvent.change(input, { target: { value: 'test' } });
    68→
    69→      // Should not be called immediately
    70→      expect(onChange).not.toHaveBeenCalled();
    71→
    72→      // Fast-forward past debounce time
    73→      vi.advanceTimersByTime(300);
    74→
    75→      expect(onChange).toHaveBeenCalledWith('test');
    76→      expect(onChange).toHaveBeenCalledTimes(1);
    77→    });
    78→
    79→    it('should use custom debounce delay', async () => {
    80→      const onChange = vi.fn();
    81→      render(<SearchBar value="" onChange={onChange} debounceMs={500} />);
    82→
    83→      const input = screen.getByRole('searchbox');
    84→      fireEvent.change(input, { target: { value: 'test' } });
    85→
    86→      // At 300ms, should not be called
    87→      vi.advanceTimersByTime(300);
    88→      expect(onChange).not.toHaveBeenCalled();
