          onToggleTag={vi.fn()}
        />
      );

      const checkboxes = screen.getAllByRole('checkbox');
      expect(checkboxes.length).toBe(3);
    });

    it('should have group role on tag container', () => {
      render(
        <SidebarNavigation
          collections={[]}
          tags={mockTags}
          onSelectCollection={vi.fn()}
